SELECT 0 ORDEN,         COMPANIA.NOMBRE COMPANIA,          TO_NUMBER(TO_CHAR(FECHA,'MM')) MES         ,TIPO_CPTE         ,COMPROBANTE         ,SUM(VALOR_DEBITO) DEBITO         ,SUM(VALOR_CREDITO) CREDITO         ,SUM(VALOR_DEBITO - VALOR_CREDITO) DIFERENCIA   FROM DETALLE_COMPROBANTE_CNT INNER JOIN COMPANIA     ON DETALLE_COMPROBANTE_CNT.COMPANIA = COMPANIA.CODIGO   WHERE  COMPANIA IN($P{PR_COMPANIACONSOLIDADORA})   AND ANO = $P{PR_ANIO}   GROUP BY 0,            COMPANIA.NOMBRE,              TO_NUMBER(TO_CHAR(FECHA,'MM')),            TIPO_CPTE,            COMPROBANTE   HAVING SUM(VALOR_DEBITO - VALOR_CREDITO)<>0              UNION ALL   SELECT 1 ORDEN,          COMPANIA.NOMBRE COMPANIA,          TO_NUMBER(TO_CHAR(FECHA,'MM')) MES         ,TIPO_CPTE         ,COMPROBANTE         ,SUM(VALOR_DEBITO) DEBITO         ,SUM(VALOR_CREDITO) CREDITO         ,SUM(VALOR_DEBITO - VALOR_CREDITO) DIFERENCIA   FROM DETALLE_COMPROBANTE_CNT INNER JOIN COMPANIA     ON DETALLE_COMPROBANTE_CNT.COMPANIA = COMPANIA.CODIGO   WHERE  COMPANIA IN(SELECT NITCOMPANIA                      FROM   CONSOLIDADA                       WHERE  COMPANIACON= $P{PR_COMPANIACONSOLIDADORA})   AND ANO = $P{PR_ANIO}   GROUP BY 1,            COMPANIA.NOMBRE,             TO_NUMBER(TO_CHAR(FECHA,'MM')),            TIPO_CPTE,            COMPROBANTE   HAVING SUM(VALOR_DEBITO - VALOR_CREDITO)<>0   ORDER BY MES,            ORDEN,             COMPANIA,            TIPO_CPTE,            COMPROBANTE        
